part of '../view.dart';class AppTabIcon extends StatelessWidget {  const AppTabIcon({    super.key,    required this.asset,    required this.selected,    required this.width,    required this.height,  });  final String asset;  final bool selected;  final double width;  final double height;  @override  Widget build(BuildContext context) {    return Tab(      icon: Image.asset(        asset,        width: width,        height: height,        color: selected            ? AppColors.primary            : Colors.grey,      ),    );  }}